import type { IIFEScriptName } from './store';

import { isTestEnv } from '@nordic/utils/validation';

import { getContext } from '../storage';

export function getRenderingIIFESource(name: IIFEScriptName) {
  if (__DEV__ && isTestEnv()) {
    return null;
  }

  const { iifeScripts } = getContext();
  const src = iifeScripts.get(name);

  if (!src) {
    return null;
  }

  // Only the first one should inject the script
  iifeScripts.delete(name);

  return src;
}
